  ('medical-tech-moex-16914', 'medical-tech', 'medical-tech-moex-097-716b3930', 'sub-medical-tech-07', NULL, 'single_choice', '關於Catalase陰性之α-溶血性革蘭氏陽性球菌的鑑定，使用bile esculin agar及optochin test之外，再 增加下列何項試驗即可鑑別較常見的肺炎鏈球菌、D群鏈球菌及腸球菌？', '["6.5% NaCl耐受試驗（growth on 6.5% NaCl broth）", "膽鹽溶解試驗（bile solubility test）", "Porphyrin test", "Leucine aminopeptidase（LAP）test"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:06+00:00", "source_pdf_sha1": "56b2a3476c34", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "108", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學及臨床微生物學（包括細菌與黴菌）", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 71, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
